   291→// Serve skill.md for agents to read
   292→import { readFileSync, existsSync } from 'fs';
   293→import { resolve } from 'path';
   294→
   295→const skillPaths = [
   296→    resolve(process.cwd(), '../../skill.md'),   // Railway: /app/apps/api -> /app/skill.md
   297→    resolve(process.cwd(), 'skill.md'),          // if cwd is repo root
   298→    resolve(__dirname, '../../../skill.md'),      // relative to dist/
   299→];
   300→const skillPath = skillPaths.find(p => existsSync(p));
   301→const skillContent = skillPath ? readFileSync(skillPath, 'utf-8') : '# skill.md not found';
