   316→                    console.error('⚠️  Escrow poller failed (non-fatal):', err.message);
   317→                });
   318→            } catch (err: any) {
   319→                console.warn('⚠️  RPC manager load failed (non-fatal) — escrow poller will not start:', err.message);
   320→            }
   321→        } else {
   322→            console.warn('⚠️  Escrow not configured (missing contract address or operator key) — poller will not start');
   323→        }
   324→
   325→        // // ClawHub skill catalog sync (runs on startup + every 24h)
   326→        // startClawhubSyncJob(server).catch((err) => {
   327→        //     console.error('⚠️  ClawHub sync job failed (non-fatal):', err.message);
   328→        // });
   329→
   330→        // Backfill verification_config for skills missing it (startup + every 6h)
   331→        const { startVerificationConfigBackfillJob } = await import('./modules/clawhub/verification-config-backfill.job');
   332→        startVerificationConfigBackfillJob(server).catch((err) => {
   333→            console.error('⚠️  Verification config backfill failed (non-fatal):', err.message);
   334→        });
   335→
   336→        const port = parseInt(process.env.PORT || '3000', 10);
   337→        // Railway requires :: (IPv6) to expose service on public/private network
   338→        await server.listen({ port, host: '::' });
   339→        console.log(`Server listening on http://localhost:${port}`);
   340→        console.log(`Docs available at http://localhost:${port}/docs`);
   341→
   342→        // Start Telegram bot polling after server is ready
   343→        if (telegramService) {
   344→            telegramService.startPolling().catch((err) => {
   345→                console.error('⚠️  Telegram bot polling failed (non-fatal):', err.message);
   346→                // Don't crash the server — bot can still send messages via API
   347→            });
   348→        }
   349→    } catch (err) {
   350→        server.log.error(err);
   351→        await prisma.$disconnect();
   352→        const { disconnectTestnetPrisma } = await import('./modules/admin/admin.prisma');
   353→        await disconnectTestnetPrisma();
   354→        process.exit(1);
   355→    }
   356→};
