    44→    tokenProvider: z.string().optional(),
    45→    tokenAmount: z.number().optional(),
    46→    startAt: z.string().datetime().optional(),
    47→    expiresAt: z.string().datetime().optional(),
    48→    tags: z.array(z.string()).default([]),
