    73→export async function questsRoutes(server: FastifyInstance) {
    74→    // List Quests
    75→    server.get(
    76→        '/',
    77→        {
    78→            schema: {
    79→                tags: ['Quests'],
    80→                summary: 'List available quests',
    81→                querystring: z.object({
    82→                    status: z.union([z.nativeEnum(QUEST_STATUS), z.literal('ended')]).optional(),
    83→                    type: z.nativeEnum(QUEST_TYPE).optional(),
    84→                    limit: z.coerce.number().int().min(1).max(100).default(50),
    85→                    offset: z.coerce.number().int().min(0).default(0),
    86→                }),
    87→                response: {
    88→                    200: z.array(QuestSchema),
    89→                },
    90→            },
    91→        },
    92→        async (request) => {
    93→            const { status, type, limit, offset } = request.query as any;
    94→
    95→            const where: any = {};
    96→            if (status === 'ended') {
    97→                // Special alias: return all terminal-state quests
    98→                where.status = { in: ['completed', 'expired', 'cancelled'] };
    99→            } else if (status) {
   100→                where.status = status;
