            email: cachedUser.email,
            username: cachedUser.username,
            displayName: cachedUser.displayName,
            supabaseId,
            role: cachedUser.role ?? 'user',
        };
        return;
    }

    // ── Find or create local Prisma user ──────────────────────────────────────
    let user = await server.prisma.user.findUnique({
