     6→/** Simple in-memory TTL cache. No external dependencies. */
     7→export class TtlCache<T> {
     8→    private store = new Map<string, CacheEntry<T>>();
     9→    private interval: NodeJS.Timeout;
    10→
    11→    constructor(cleanupIntervalMs = 5 * 60_000) {
    12→        this.interval = setInterval(() => this.cleanup(), cleanupIntervalMs);
    13→        // unref so this timer doesn't block process exit or slow down tests
    14→        this.interval.unref();
    15→    }
    16→
    17→    get(key: string): T | undefined {
    18→        const entry = this.store.get(key);
    19→        if (!entry) return undefined;
    20→        if (Date.now() > entry.expiresAt) {
    21→            this.store.delete(key);
    22→            return undefined;
    23→        }
    24→        return entry.data;
    25→    }
    26→
    27→    set(key: string, value: T, ttlMs: number): void {
    28→        this.store.set(key, { data: value, expiresAt: Date.now() + ttlMs });
    29→    }
    30→
    31→    delete(key: string): void {
    32→        this.store.delete(key);
    33→    }
    34→
    35→    /** Delete all keys that start with the given prefix. */
    36→    deleteByPrefix(prefix: string): void {
    37→        for (const key of this.store.keys()) {
    38→            if (key.startsWith(prefix)) this.store.delete(key);
    39→        }
    40→    }
    41→
    42→    /** Clear the cleanup interval. Call in tests and graceful shutdown. */
    43→    destroy(): void {
    44→        clearInterval(this.interval);
    45→    }
    46→
    47→    private cleanup(): void {
    48→        const now = Date.now();
    49→        for (const [key, entry] of this.store.entries()) {
    50→            if (now > entry.expiresAt) this.store.delete(key);
    51→        }
    52→    }
    53→}
