        {/* 4. Latest Bounties */}
        <LatestBounties />

        {/* 5. How It Works + FAQs — side by side on desktop */}
        <div className="grid grid-cols-1 lg:grid-cols-2 border border-border rounded divide-y lg:divide-y-0 lg:divide-x divide-border">
          <HowItWorks />
          <FAQSection />
        </div>
      </div>
    </>
  );
}

