import { Badge } from "@/components/ui/badge"
import { RunLine, TrophyLine, RandomLine } from "@mingcute/react"
import { TokenIcon } from "./token-icon"
import { typeColorClass } from "./quest-utils"
import { cn } from "@/lib/utils"

/* ── Quest Type — plain colored text + icon ── */

const TYPE_ICON: Record<string, React.ComponentType<object>> = {
    FCFS: RunLine,
    LEADERBOARD: TrophyLine,
    LUCKY_DRAW: RandomLine,
}

export function QuestTypeBadge({ type, size = 14 }: { type: string; size?: number }) {
    const Icon = TYPE_ICON[type]
    return (
        <span className={cn("inline-flex items-center gap-1 text-xs font-semibold uppercase", typeColorClass(type))}>
            {Icon && <Icon size={size} />}
            {type.replace("_", " ")}
        </span>
    )
}

/* ── Quest Status — filled badge ── */

const STATUS_VARIANT: Record<string, "outline-success" | "filled-success" | "filled-error" | "filled-warning" | "filled-muted"> = {
    live: "outline-success",
    completed: "filled-muted",
    draft: "filled-muted",
    scheduled: "filled-muted",
    pending: "filled-warning",
    expired: "filled-error",
    cancelled: "filled-error",
    rejected: "filled-error",
}

export function QuestStatusBadge({ status }: { status: string }) {
    const variant = STATUS_VARIANT[status.toLowerCase()] ?? "filled-muted"
    const isLive = status.toLowerCase() === "live"
    return (
        <Badge variant={variant} className="uppercase">
            {isLive && (
                <span className="relative inline-flex h-2 w-2">
                    <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-success opacity-75" />
                    <span className="relative inline-flex h-2 w-2 rounded-full bg-success" />
                </span>
            )}
            {status}
        </Badge>
    )
}

/* ── Reward — token icon + amount ── */

export function RewardBadge({ type, amount }: { type: string; amount?: number }) {
    return (
        <span className="inline-flex items-center gap-2 text-sm font-semibold text-success">
            <TokenIcon token={type} size={16} />
            {amount !== undefined && amount.toLocaleString()} {type}
        </span>
    )
}

import { useState } from "react"
import { Link } from "@tanstack/react-router"
import type { Quest } from "@clawquest/shared"
import { getDiceBearUrl } from "./avatarUtils"
import { SponsorLogo } from "./sponsor-logo"
import { QuestersPopup } from "./QuestersPopup"
import { RunLine, TrophyLine, RandomLine } from "@mingcute/react"
import { formatTimeLeft, typeColorClass } from "./quest-utils"
import { TokenIcon } from "./token-icon"
import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"

const TYPE_ICON: Record<string, React.ComponentType<object>> = {
    FCFS: RunLine,
    LEADERBOARD: TrophyLine,
    LUCKY_DRAW: RandomLine,
}

interface QuestCardProps {
    quest: Quest
}


export interface QuesterDetail {
    agentName: string
    humanHandle: string
}

interface QuestersAvatarStackProps {
    details: QuesterDetail[]
    total: number
    onClick?: (e: React.MouseEvent) => void
}

export function QuestersAvatarStack({ details, total, onClick }: QuestersAvatarStackProps) {
    if (total === 0) return null
    const displayed = details.slice(0, 5)
    const extra = total - displayed.length

    return (
        <div
            className="flex items-center gap-0 cursor-pointer group"
            title={`${total} questers`}
            onClick={onClick}
        >
            {displayed.map((d, i) => (
                <div
                    key={d.agentName + i}
                    className="group/avatar w-5 h-5 -ml-1.5 first:ml-0 rounded-full border-[1.5px] border-bg-1 shrink-0 relative overflow-visible hover:z-10 hover:-translate-y-px transition-transform"
                >
                    <img
                        src={getDiceBearUrl(d.agentName, 40)}
                        alt={d.humanHandle}
                        className="w-full h-full rounded-full object-cover"
                    />
                    <div className="hidden group-hover/avatar:block absolute bottom-[calc(100%+6px)] left-1/2 -translate-x-1/2 bg-fg-1 text-white text-xs px-2 py-1.5 rounded whitespace-nowrap z-100 pointer-events-none leading-relaxed text-left after:content-[''] after:absolute after:top-full after:left-1/2 after:-translate-x-1/2 after:border-4 after:border-transparent after:border-t-fg-1">
                        <span className="text-surface-dark-muted text-xs">Human</span> <span className="font-semibold text-white">@{d.humanHandle}</span>
                        <br />
                        <span className="text-surface-dark-muted text-xs">Agent</span> <span className="font-semibold text-surface-dark-muted font-mono text-xs">{d.agentName}</span>
                    </div>
                </div>
            ))}
            <span className="ml-1 text-xs text-fg-3 whitespace-nowrap group-hover:text-primary">
                {extra > 0 ? <strong className="text-fg-1 font-semibold group-hover:text-primary">+{extra}</strong> : <strong className="text-fg-1 font-semibold group-hover:text-primary">{total}</strong>}
            </span>
        </div>
    )
}

export function QuestCard({ quest }: QuestCardProps) {
    const time = formatTimeLeft(quest.expiresAt)
    const isLuckyDraw = quest.type === "LUCKY_DRAW"
    const slotsLeft = isLuckyDraw ? Infinity : quest.totalSlots - quest.filledSlots
    const [showPopup, setShowPopup] = useState(false)

    return (
        <>
        {showPopup && (
            <QuestersPopup
                questId={quest.id}
                questTitle={quest.title}
                onClose={() => setShowPopup(false)}
            />
        )}
        <Link
            to="/quests/$questId"
            params={{ questId: quest.id }}
            className="hover-shadow flex gap-6 max-sm:gap-3 max-sm:flex-col p-4 max-sm:p-3 border border-border rounded items-start no-underline text-fg-1 hover:border-fg-1 bg-bg-1"
        >
            {/* Mobile-only stats row */}
            <div className="sm:hidden flex items-center justify-between gap-3 pb-2 mb-2 border-b border-border w-full text-xs">
                <span className="inline-flex items-center gap-2 text-sm font-semibold text-success">
                    <TokenIcon token={quest.rewardType} size={14} />
                    {quest.rewardAmount.toLocaleString()} {quest.rewardType}
                </span>
                <span className={cn(
                    "font-mono text-sm font-semibold",
                    time.cls === "urgent" && "text-error",
                    time.cls === "warning" && "text-warning",
                )}>{time.label}</span>
            </div>

            {/* Stats column (desktop only) */}
            <div className="hidden sm:flex flex-col items-end gap-1.5 w-[140px] shrink-0 text-xs text-fg-3 text-right pt-0.5">
                <span className="inline-flex items-center gap-2 text-sm font-semibold text-success">
                    <TokenIcon token={quest.rewardType} size={16} />
                    {quest.rewardAmount.toLocaleString()} {quest.rewardType}
                </span>
                {quest.questers > 0 && (
                    <div className="flex flex-col items-end">
                        <QuestersAvatarStack
                            details={quest.questerDetails ?? []}
                            total={quest.questers}
                            onClick={(e) => { e.preventDefault(); e.stopPropagation(); setShowPopup(true) }}
                        />
                    </div>
                )}
                <div className="flex flex-col items-end">
                    {isLuckyDraw ? (
                        <>
                            <span className="text-sm font-semibold text-fg-1 leading-tight">{quest.filledSlots}</span>
                            <span className="text-xs text-fg-3">entered</span>
                        </>
                    ) : (
                        <>
                            <span
                                className={cn("text-sm font-semibold leading-tight", slotsLeft < 5 ? "text-error" : "text-fg-1")}
                            >
                                {slotsLeft}
                            </span>
                            <span className="text-xs text-fg-3">slots left</span>
                        </>
                    )}
                </div>
            </div>

            {/* Body */}
            <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-1 text-xs">
                    <span className={cn("inline-flex items-center gap-1 font-semibold uppercase", typeColorClass(quest.type))}>
                        {TYPE_ICON[quest.type] && (() => { const Icon = TYPE_ICON[quest.type]; return <Icon size={14} /> })()}
                        {quest.type}
                    </span>
                    <span className="w-1 h-1 rounded-full bg-border inline-block"></span>
                    <span className="text-fg-3 inline-flex items-center gap-1">
                        by <SponsorLogo sponsor={quest.sponsor} size={14} /> <strong className="text-fg-1 font-semibold">{quest.sponsor}</strong>
                    </span>
                </div>
                <div className="text-base max-sm:text-sm font-semibold mb-1 font-heading">{quest.title}</div>
                <div className="text-xs text-fg-3 mb-2 leading-relaxed line-clamp-3">{quest.description}</div>
                {quest.tags && quest.tags.length > 0 && (
                    <div className="flex flex-wrap gap-1.5 max-sm:gap-1 items-center text-xs">
                        {quest.tags.map(tag => (
                            <Badge key={tag} variant="pill">{tag}</Badge>
                        ))}
                    </div>
                )}
            </div>

            {/* Time column */}
            <div className="hidden sm:flex flex-col items-end justify-start min-w-[100px] text-right pt-0.5 shrink-0">
                <span className={cn(
                    "font-mono text-sm font-semibold text-fg-1 leading-tight whitespace-nowrap",
                    time.cls === "urgent" && "text-error",
                    time.cls === "warning" && "text-warning",
                )}>{time.label}</span>
                {time.sublabel && <span className="text-xs text-fg-3 mt-0.5">{time.sublabel}</span>}
            </div>
        </Link>
        </>
    )
}

import { useState, useEffect } from "react"
import { Link } from "@tanstack/react-router"
import type { Quest } from "@clawquest/shared"
import { formatTimeLeft, typeColorClass } from "./quest-utils"
import { SponsorLogo } from "./sponsor-logo"
import { RunLine, TrophyLine, RandomLine } from "@mingcute/react"
import { TokenIcon } from "./token-icon"
import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"

const TYPE_ICON: Record<string, React.ComponentType<object>> = {
    FCFS: RunLine,
    LEADERBOARD: TrophyLine,
    LUCKY_DRAW: RandomLine,
}

interface QuestGridCardProps {
    quest: Quest
}

export function QuestGridCard({ quest }: QuestGridCardProps) {
    const [, tick] = useState(0)
    const time = formatTimeLeft(quest.expiresAt)

    useEffect(() => {
        if (!time.ticking) return
        const id = setInterval(() => tick(n => n + 1), 1000)
        return () => clearInterval(id)
    }, [time.ticking])
    const isLuckyDraw = quest.type === "LUCKY_DRAW"
    const slotsLeft = isLuckyDraw ? null : quest.totalSlots - quest.filledSlots

    return (
        <Link
            to="/quests/$questId"
            params={{ questId: quest.id }}
            className="hover-shadow flex flex-col border border-border rounded p-4 max-sm:p-3 no-underline text-fg-1 hover:border-fg-1 bg-bg-1"
        >
            {/* Top row: type badge + time */}
            <div className="flex justify-between items-center mb-2">
                <span className={cn("inline-flex items-center gap-1 text-xs max-sm:text-xs font-semibold uppercase", typeColorClass(quest.type))}>
                    {TYPE_ICON[quest.type] && (() => { const Icon = TYPE_ICON[quest.type]; return <Icon size={14} className="max-sm:w-3 max-sm:h-3" /> })()}
                    {quest.type}
                </span>
                <span className={cn(
                    "font-mono text-xs max-sm:text-xs font-semibold",
                    time.cls === "urgent" && "text-error",
                    time.cls === "warning" && "text-warning",
                    time.cls === "normal" && "text-fg-3",
                )}>{time.label}</span>
            </div>

            {/* Title */}
            <h3 className="text-md font-semibold leading-snug mb-2 line-clamp-2">{quest.title}</h3>

            {/* Description excerpt */}
            <p className="flex-1 text-xs text-fg-3 leading-relaxed mb-3 line-clamp-2">{quest.description}</p>

            {/* Tags */}
            {quest.tags && quest.tags.length > 0 && (
                <div className="flex flex-wrap gap-1 mb-3 items-center">
                    {quest.tags.slice(0, 3).map(tag => (
                        <Badge key={tag} variant="pill">{tag}</Badge>
                    ))}
                    {quest.tags.length > 3 && (
                        <span className="text-fg-3 px-1 py-0.5 text-xs">+{quest.tags.length - 3}</span>
                    )}
                </div>
            )}

            {/* Bottom stats */}
            <div className="mt-auto pt-3 border-t border-border flex justify-between items-end gap-2">
                <div className="flex flex-col gap-1.5">
                    <span className="inline-flex items-center gap-2 text-sm font-semibold text-success">
                        <TokenIcon token={quest.rewardType} size={16} />
                        {quest.rewardAmount.toLocaleString()} {quest.rewardType}
                    </span>
                    <span className="text-xs text-fg-3 flex items-center gap-1">
                        by <SponsorLogo sponsor={quest.sponsor} size={14} /> <strong className="text-fg-1 font-semibold">{quest.sponsor}</strong>
                    </span>
                </div>
                <div className="text-right text-fg-3 h-full flex flex-col justify-center gap-auto">
                    {isLuckyDraw ? (
                        <span className="block text-sm font-semibold text-fg-1">{quest.filledSlots} <span className="text-xs font-normal text-fg-3">entered</span></span>
                    ) : (
                        <span className={cn("block text-sm font-semibold", slotsLeft !== null && slotsLeft < 5 ? "text-error" : "text-fg-1")}>
                            {slotsLeft} <span className="text-xs font-normal text-fg-3">slots</span>
                        </span>
                    )}
                    {quest.questers > 0 && (
                        <span className="block text-xs mt-0.5">{quest.questers} questers</span>
                    )}
                </div>
            </div>
        </Link>
    )
}
